from flask import Flask, request, session, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)  # Generate a secret key for the app

@app.route('/update-profile', methods=['POST'])
def update_profile():
    if 'csrf_token' not in session or request.form['csrf_token'] != session['csrf_token']:
        return jsonify({'error': 'CSRF token mismatch'}), 401
    
    email = request.form.get('email')
    password = request.form.get('password')
    two_factor_auth = request.form.get('two_factor_auth')

    if not all([email, password]):
        return jsonify({'error': 'Missing required fields'}), 400

    # Update user profile
    session['email'] = email
    if password:
        session['password_hash'] = generate_password_hash(password)
    if two_factor_auth:
        session['two_factor_auth'] = two_factor_auth

    return jsonify({'message': 'Profile updated successfully'}), 200

@app.before_request
def _require_csrf_token():
    if request.method == 'POST':
        session.pop('csrf_token', None)
        session['csrf_token'] = str(os.urandom(16))

if __name__ == '__main__':
    app.run(debug=True)